int create_key_from_ireq(struct ireq *iq, int ixnum, int isDelete, char **tail,
                         int *taillen, char *mangled_key, char *partial_datacopy_tail,
                         const char *inbuf, int inbuflen, char *outbuf)
{
    int rc = 0;
    dbtable *db = iq->usedb;

    if (isDelete)
        memcpy(outbuf, iq->idxDelete[ixnum], db->ix_keylen[ixnum]);
    else
        memcpy(outbuf, iq->idxInsert[ixnum], db->ix_keylen[ixnum]);

    // autoinc value is not set on replicant, set it now
    struct schema *idx_schema = get_schema(db, ixnum);
    struct schema *schema = get_schema(db, -1);
    int rec_srt_off = gbl_sort_nulls_correctly ? 0 : 1;
    char temp[9];
    char *check_for_resolve_master;
    for (int nfield = 0; nfield < idx_schema->nmembers; nfield++) {
        const struct field *idx_field = &idx_schema->member[nfield];
        // TODO: expression idx
        if (idx_field->isExpr)
            continue;
        if (idx_field->in_default_type != SERVER_SEQUENCE)
            continue;

        if (idx_field->flags & INDEX_DESCEND) { // need to undo to check for resolve master bit
            assert(idx_field->len <= sizeof(temp));
            memcpy(temp, outbuf + idx_field->offset, idx_field->len);
            xorbuf(temp + rec_srt_off, idx_field->len - rec_srt_off);
            check_for_resolve_master = temp;
        } else
            check_for_resolve_master = outbuf + idx_field->offset;

        if (!stype_is_resolve_master(check_for_resolve_master))
            continue;
        // grab actual autoinc value from the record
        const struct field *field = &schema->member[idx_field->idx];
        assert(idx_field->len == field->len);
        memcpy(outbuf + idx_field->offset, inbuf + field->offset, idx_field->len);
        if (idx_field->flags & INDEX_DESCEND)
            xorbuf((outbuf + idx_field->offset) + rec_srt_off, idx_field->len - rec_srt_off);
    }

    if (db->ix_datacopy[ixnum]) {
        assert(db->ix_collattr[ixnum] == 0);

        if (db->ix_datacopy[ixnum] > 1) {
            /* the key has decimals */
            rc = extract_decimal_quantum(db, ixnum, outbuf, mangled_key,
                                         4 * (db->ix_datacopy[ixnum] - 1),
                                         taillen);
        }
        if (rc) {
            if (tail) {
                *tail = NULL;
                *taillen = 0;
            }
            rc = -1; /* callers like -1 */
        } else if (tail) {
            struct schema *fromsch = get_schema(db, -1);
            struct schema *tosch = get_schema(db, ixnum);
            if (partial_datacopy_tail && (tosch->flags & SCHEMA_PARTIALDATACOPY)) {
                rc = stag_to_stag_buf_schemas(db, fromsch, tosch->partial_datacopy,
                                              inbuf, partial_datacopy_tail, iq->tzname);
                if (rc)
                    return rc;

                *tail = (char *)partial_datacopy_tail;
                *taillen = get_size_of_schema(tosch->partial_datacopy);
            } else {
                *tail = (char *)inbuf;
                *taillen = inbuflen;
            }
        }
    } else if (db->ix_collattr[ixnum]) {
        assert(db->ix_datacopy[ixnum] == 0);

        rc = extract_decimal_quantum(db, ixnum, outbuf, mangled_key,
                                     4 * db->ix_collattr[ixnum], taillen);
        if (rc) {
            if (tail) {
                *tail = NULL;
                *taillen = 0;
            }
            rc = -1; /* callers like -1 */
        } else {
            if (tail) {
                *tail = mangled_key;
            }
        }
    } else {
        if (tail) {
            *tail = NULL;
            *taillen = 0;
        }
    }

    return rc;
}

